import Marquee from "react-fast-marquee";
import { motion } from "framer-motion";

const videoItems = [
  { id: "v1", src: "/assets/videos/cooking.mp4" },
  { id: "v2", src: "/assets/videos/vid2.mp4" },
  { id: "v3", src: "/assets/videos/vid3.mp4" },
  { id: "v4", src: "/assets/videos/vid5.mp4" },
  { id: "v5", src: "/assets/videos/vid6.mp4" }
];

const imageItems = [
  "/assets/amb.jpg",
  "/assets/apr.jpg",
  "/assets/ballent.jpg",
  "/assets/bl.jpg",
  "/assets/bn.jpg",
  "/assets/dj.jpg",
  "/assets/dri.jpg",
  "/assets/f1.jpg",
  "/assets/grp.jpg",
  "/assets/nod.jpg",
  "/assets/pic.jpg",
  "/assets/piz.jpg"
];

const MovingGallery = () => {
  return (
    <section className="py-24 bg-black overflow-hidden">
      <div className="text-center mb-24 px-8">
        <motion.span 
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          className="inline-block font-accent text-gold text-sm tracking-[0.4em] uppercase px-8 py-3 bg-black/40 rounded-full backdrop-blur-sm mb-8"
        >
          Experience The Vibe
        </motion.span>
        <motion.h2 
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          className="font-heading text-5xl md:text-7xl text-white tracking-tight leading-none"
        >
          Corridor in Motion
        </motion.h2>
      </div>

      {/* Videos - Portrait Seamless No Gap */}
      <motion.div 
        initial={{ opacity: 0 }}
        whileInView={{ opacity: 1 }}
        className="mb-24"
      >
        <Marquee speed={26} gradient={false} pauseOnHover>
          {videoItems.concat(videoItems).map((video) => (
            <video
              key={video.id}
              src={video.src}
              className="w-[215px] md:w-[265px] h-[360px] md:h-[450px] object-cover rounded-2xl shadow-2xl mr-0 inline-block [margin-right:0px]"
              muted
              autoPlay
              loop
              playsInline
              preload="metadata"
            />
          ))}
        </Marquee>
      </motion.div>

      {/* Images Row 1 LTR Seamless */}
      <motion.div 
        initial={{ opacity: 0 }}
        whileInView={{ opacity: 1 }}
        className="mb-24"
      >
        <Marquee speed={60} gradient={false} pauseOnHover>
          {imageItems.slice(0,10).map((src, index) => (
            <motion.img
              key={index}
              src={src}
              className="w-[300px] md:w-[380px] h-[200px] md:h-[260px] object-cover rounded-xl mr-0 inline-block grayscale hover:grayscale-0 shadow-xl hover:scale-[1.02] hover:shadow-2xl transition-all duration-400"
              loading="lazy"
            />
          ))}
        </Marquee>
      </motion.div>

      {/* Images Row 2 RTL Seamless */}
      <motion.div 
        initial={{ opacity: 0 }}
        whileInView={{ opacity: 1 }}
      >
        <Marquee speed={60} direction="right" gradient={false} pauseOnHover>
          {imageItems.slice(0,6).map((src, index) => (
            <motion.img
              key={"rtl" + index}
              src={src}
              className="w-[300px] md:w-[380px] h-[200px] md:h-[260px] object-cover rounded-xl mr-0 inline-block grayscale hover:grayscale-0 shadow-xl hover:scale-[1.02] hover:shadow-2xl transition-all duration-400"
              loading="lazy"
            />
          ))}
        </Marquee>
      </motion.div>
    </section>
  );
};

export default MovingGallery;
